    "inlineSchema": "generator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ==========================\n// USERS & AUTHENTICATION\n// ==========================\n\nmodel User {\n  id String @id @default(cuid())\n\n  email String @unique\n\n  password String\n\n  isActive Boolean @default(true)\n\n  roles UserRole[]\n\n  director Director?\n\n  teacher Teacher?\n\n  parent Parent?\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// ROLES & PERMISSIONS\n// ==========================\n\nmodel Role {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  description String?\n\n  users UserRole[]\n\n  permissions RolePermission[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\nmodel Permission {\n  id String @id @default(cuid())\n\n  name String @unique\n\n  description String?\n\n  roles RolePermission[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// USER ROLE CONNECTION\n// ==========================\n\nmodel UserRole {\n  id String @id @default(cuid())\n\n  userId String\n\n  roleId String\n\n  user User @relation(fields: [userId], references: [id])\n\n  role Role @relation(fields: [roleId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([userId, roleId])\n}\n\n// ==========================\n// ROLE PERMISSION CONNECTION\n// ==========================\n\nmodel RolePermission {\n  id String @id @default(cuid())\n\n  roleId String\n\n  permissionId String\n\n  role Role @relation(fields: [roleId], references: [id])\n\n  permission Permission @relation(fields: [permissionId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([roleId, permissionId])\n}\n\n// ==========================\n// DIRECTOR\n// ==========================\n\nmodel Director {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// TEACHERS\n// ==========================\n\nmodel Teacher {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// PARENTS\n// ==========================\n\nmodel Parent {\n  id String @id @default(cuid())\n\n  firstName String\n\n  lastName String\n\n  phone String?\n\n  relationship String?\n  // Father\n  // Mother\n  // Guardian\n\n  userId String @unique\n\n  user User @relation(fields: [userId], references: [id])\n\n  students StudentParent[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// STUDENTS\n// ==========================\n\nmodel Student {\n  id String @id @default(cuid())\n\n  admissionNumber String @unique\n\n  firstName String\n\n  lastName String\n\n  dateOfBirth DateTime?\n\n  gender String?\n\n  isActive Boolean @default(true)\n\n  parents StudentParent[]\n\n  createdAt DateTime @default(now())\n\n  updatedAt DateTime @updatedAt\n}\n\n// ==========================\n// STUDENT - PARENT RELATION\n// ==========================\n\nmodel StudentParent {\n  id String @id @default(cuid())\n\n  studentId String\n\n  parentId String\n\n  relationship String?\n  // Father\n  // Mother\n  // Guardian\n\n  student Student @relation(fields: [studentId], references: [id])\n\n  parent Parent @relation(fields: [parentId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  @@unique([studentId, parentId])\n}\n",
